/**
 * Processes the retrieved quota records.
 *
 * This node:
 * - finds the current user's quota record
 * - finds the global daily quota record
 * - extracts request counters
 * - provides default values if no record exists
 *
 * The resulting data is used for rate limit validation.
 */

const request = $('Generate Request Metadata').first().json;

const rows = $input.all()
  .map(item => item.json)
  .filter(row => row.quotaKey);

const ipRow = rows.find(
  row => row.quotaKey === request.quotaKey
);

const globalRow = rows.find(
  row => row.quotaKey === request.globalQuotaKey
);

return [{
  json: {
    ...request,

    ipCount: Number(ipRow?.count ?? 0),
    globalCount: Number(globalRow?.count ?? 0),

    lastRequest: Number(ipRow?.lastRequest ?? 0),

    ipRowExists: Boolean(ipRow),
    globalRowExists: Boolean(globalRow)
  }
}];

/**
 * Prepares request metadata for the workflow.
 *
 * This node:
 * - extracts the client's IP address
 * - creates the current date
 * - records the request timestamp
 * - generates quota keys for daily rate limiting
 *
 * These values are used later to identify users,
 * enforce request limits and log requests.
 */
const headers = $json.headers ?? {};
const forwardedFor = headers['x-forwarded-for'];

const rawIp =
  headers['cf-connecting-ip'] ||
  headers['x-real-ip'] ||
  (forwardedFor ? forwardedFor.split(',')[0] : '') ||
  '127.0.0.1';

const ip = rawIp.trim().replace(/^::ffff:/, '');

const date = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Europe/Berlin'
}).format(new Date());

return [{
  json: {
    ...$json,
    ip,
    date,
    requestTime: Date.now(),
    quotaKey: `${date}|${ip}`,
    globalQuotaKey: `${date}|GLOBAL`
  }
}];

/**
 * Updates the user and global quota records.
 *
 * This node:
 * - increments the user's request counter
 * - increments the global request counter
 * - updates the timestamp of the latest request
 *
 * The resulting records are written back to the
 * quota storage in the next step.
 */
const data = $input.first().json;

return [
  {
    json: {
      quotaKey: data.quotaKey,
      ip: data.ip,
      date: data.date,
      count: Number(data.ipCount ?? 0) + 1,
      lastRequest: Number(data.requestTime)
    }
  },
  {
    json: {
      quotaKey: data.globalQuotaKey,
      ip: '',
      date: data.date,
      count: Number(data.globalCount ?? 0) + 1,
      lastRequest: Number(data.requestTime)
    }
  }
];

const output = $input.first().json.output;

const cleanedOutput = output
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

const parsed = JSON.parse(cleanedOutput);

return [
  {
    json: parsed
  }
]

/**
 * Prepares the generated recipes for storage.
 *
 * This node:
 * - iterates over all generated recipes
 * - adds a creation timestamp to each recipe
 * - returns each recipe as a separate n8n item
 *
 * The prepared records are stored in the database
 * in the following workflow step.
 */
const recipes = $json.recipes;

return recipes.map(recipe => ({
  json: {
    ...recipe,
    createdAt: new Date().toISOString()
  }
}));
